import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import polygonClipping from 'polygon-clipping'; // Added: Import polygon-clipping

import AnnotationTopBar from '../components/AnnotationTopBar';
import AnnotationCanvas from '../components/AnnotationCanvas';
import AnnotationListSidebar from '../components/AnnotationListSidebar';
import './Annotate.css';

export default function Annotate() {
  const navigate = useNavigate();
  const { state } = useLocation();
  const folderInfo = state?.folderInfo;

  if (!folderInfo) {
    return (
      <div style={{ padding: 20 }}>
        <h2>No folder info found. Please create a task first.</h2>
        <button onClick={() => navigate('/')}>Go Home</button>
      </div>
    );
  }

  const { folderId, taskName, labelClasses: initialLabelClasses, files } = folderInfo;

  // -------------- Annotations for each image --------------
  const [annotations, setAnnotations] = useState({});
  const [undoStack, setUndoStack] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  // Tools: move, bbox, polygon, polyline, point, ellipse, segmentation
  // default to 'move'
  const [selectedTool, setSelectedTool] = useState('move');

  // For “segmentation” specifically, we have a small dropdown (Instance, Semantic, Panoptic)
  const [segmentationType, setSegmentationType] = useState('instance');

  const [selectedLabelClass, setSelectedLabelClass] = useState(
    initialLabelClasses[0]?.name || ''
  );
  const [scale, setScale] = useState(1.0);

  const [currentLabelClasses, setLabelClasses] = useState(initialLabelClasses); // Managed as state

  const currentFileUrl = files[currentIndex]?.url;
  const currentShapes = annotations[currentFileUrl] || [];

  // State to hold image dimensions
  const [imageDimensions, setImageDimensions] = useState({ width: 0, height: 0 });

  // Whenever shapes change, store old state in undoStack
  const handleAnnotationsChange = (newShapes) => {
    const updated = {
      ...annotations,
      [currentFileUrl]: newShapes,
    };
    setUndoStack([...undoStack, annotations]);
    setRedoStack([]);
    setAnnotations(updated);
  };

  // -------------- Undo / Redo --------------
  const undo = () => {
    if (undoStack.length === 0) return;
    const prev = undoStack[undoStack.length - 1];
    setRedoStack([...redoStack, annotations]);
    setUndoStack(undoStack.slice(0, -1));
    setAnnotations(prev);
  };

  const redo = () => {
    if (redoStack.length === 0) return;
    const next = redoStack[redoStack.length - 1];
    setUndoStack([...undoStack, annotations]);
    setRedoStack(redoStack.slice(0, -1));
    setAnnotations(next);
  };

  // -------------- Deletion & Update --------------
  const handleDeleteAnnotation = (index) => {
    const arr = [...currentShapes];
    arr.splice(index, 1);
    handleAnnotationsChange(arr);
  };

  const handleUpdateAnnotation = (index, changes) => {
    const arr = [...currentShapes];
    arr[index] = { ...arr[index], ...changes };
    handleAnnotationsChange(arr);
  };

  // -------------- Navigation --------------
  const handlePrev = () => {
    if (currentIndex > 0) setCurrentIndex((i) => i - 1);
  };
  const handleNext = () => {
    if (currentIndex < files.length - 1) setCurrentIndex((i) => i + 1);
  };

  // -------------- Zoom --------------
  const handleZoomIn = () => setScale((s) => Math.min(s + 0.1, 5));
  const handleZoomOut = () => setScale((s) => Math.max(s - 0.1, 0.2));
  const handleWheelZoom = (deltaY) => {
    if (deltaY < 0) handleZoomIn();
    else handleZoomOut();
  };

  // -------------- Save --------------
  const handleSave = async () => {
    const bodyData = {
      folderId,
      taskName,
      labelClasses: currentLabelClasses, // Use state
      annotations,
    };
    try {
      const res = await fetch('http://localhost:4000/api/annotations', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(bodyData),
      });
      const data = await res.json();
      alert('Saved: ' + data.message);
    } catch (err) {
      console.error(err);
      alert('Error saving');
    }
  };

  // -------------- Keyboard Shortcuts --------------
  useEffect(() => {
    const handleKey = (e) => {
      const key = e.key;

      // Tools
      if (key === 'm' || key === 'M') {
        setSelectedTool('move');
      } else if (key === 'b' || key === 'B') {
        setSelectedTool('bbox');
      } else if (key === 'p' || key === 'P') {
        setSelectedTool('polygon');
      } else if (key === 'l' || key === 'L') {
        setSelectedTool('polyline');
      } else if (key === 'o' || key === 'O') {
        setSelectedTool('point');
      } else if (key === 'e' || key === 'E') {
        setSelectedTool('ellipse');
      }
      // Segmentation on plain "S"
      else if ((key === 's' || key === 'S') && e.ctrlKey) {
        // Ctrl+S => Save
        e.preventDefault();
        handleSave();
      } else if (key === 's' || key === 'S') {
        // Just S => Segmentation
        setSelectedTool('segmentation');
      }

      // Esc => cancel shape
      if (key === 'Escape') {
        const event = new CustomEvent('cancel-annotation');
        window.dispatchEvent(event);
      }
      // Next / Prev
      if (key === 'ArrowRight') {
        handleNext();
      } else if (key === 'ArrowLeft') {
        handlePrev();
      }

      // Undo / Redo
      if (e.ctrlKey && (key === 'z' || key === 'Z')) {
        e.preventDefault();
        undo();
      } else if (e.ctrlKey && (key === 'y' || key === 'Y')) {
        e.preventDefault();
        redo();
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
    // eslint-disable-next-line
  }, [annotations, undoStack, redoStack]);

  // -------------- Export Logic --------------
  const [exportOpen, setExportOpen] = useState(false);
  const openExport = () => setExportOpen(true);
  const closeExport = () => setExportOpen(false);

  const exportAnnotations = (format) => {
    if (format === 'coco') {
      downloadCOCO();
    } else if (format === 'yolo') {
      downloadYOLO();
    } else if (format === 'pascal') {
      downloadPascal();
    }
    closeExport();
  };

  function downloadFile(url, filename) {
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }

  function downloadCOCO() {
    alert('COCO export not yet implemented!');
  }
  function downloadYOLO() {
    alert('YOLO export not yet implemented!');
  }
  function downloadPascal() {
    alert('Pascal VOC export not yet implemented!');
  }

  // -------------- When annotation finishes => switch to move --------------
  const handleFinishShape = () => {
    setSelectedTool('move');
  };

  // -------------- Fill Background Feature -------------- // Added: Fill Background Feature
  const handleFillBackground = () => {
    if (imageDimensions.width === 0 || imageDimensions.height === 0) {
      alert('Image not loaded.');
      return;
    }

    // Prompt user for label name, default 'background'
    let labelName = prompt('Enter label name for background:', 'background');
    if (!labelName) {
      labelName = 'background';
    }

    // Check if labelName already exists
    const existingLabel = currentLabelClasses.find(
      (lc) => lc.name.toLowerCase() === labelName.toLowerCase()
    );

    let labelColor = '#000000'; // Default black

    if (existingLabel) {
      alert(
        `Label "${labelName}" already exists. Please choose a different name or use the existing label.`
      );
      return;
    }

    // Check if any existing label has the default color
    const colorConflict = currentLabelClasses.some(
      (lc) => lc.color.toLowerCase() === labelColor.toLowerCase()
    );

    if (colorConflict) {
      // Choose a different color
      const availableColors = [
        '#FF5733',
        '#33FF57',
        '#3357FF',
        '#F333FF',
        '#FF33A8',
        '#33FFF5',
        '#F5FF33',
        '#A833FF',
        '#FF8F33',
        '#33FF8F',
      ];
      const usedColors = currentLabelClasses.map((lc) => lc.color.toLowerCase());
      const newColor = availableColors.find(
        (color) => !usedColors.includes(color.toLowerCase())
      );
      if (newColor) {
        labelColor = newColor;
      } else {
        alert(
          'No available colors to assign to the background label. Please choose a different color manually.'
        );
        return;
      }
    }

    // Add the new label to labelClasses
    const updatedLabelClasses = [
      ...currentLabelClasses,
      { name: labelName, color: labelColor },
    ];
    setLabelClasses(updatedLabelClasses); // Update state

    // Prepare the image boundary polygon
    const imageWidth = imageDimensions.width;
    const imageHeight = imageDimensions.height;
    const imagePolygon = [
      [
        { x: 0, y: 0 },
        { x: imageWidth, y: 0 },
        { x: imageWidth, y: imageHeight },
        { x: 0, y: imageHeight },
      ],
    ];

    // Convert existing annotations to polygons
    const annotationPolygons = currentShapes
      .filter((ann) =>
        ['bbox', 'polygon', 'ellipse', 'segmentation'].includes(ann.type)
      )
      .map((ann) => {
        if (ann.type === 'bbox') {
          return [
            [
              { x: ann.x, y: ann.y },
              { x: ann.x + ann.width, y: ann.y },
              { x: ann.x + ann.width, y: ann.y + ann.height },
              { x: ann.x, y: ann.y + ann.height },
            ],
          ];
        } else if (ann.type === 'ellipse') {
          // Approximate ellipse with polygon
          const points = [];
          const numPoints = 32;
          for (let i = 0; i < numPoints; i++) {
            const theta = (i / numPoints) * 2 * Math.PI;
            points.push({
              x: ann.x + ann.radiusX * Math.cos(theta),
              y: ann.y + ann.radiusY * Math.sin(theta),
            });
          }
          return [points];
        } else if (ann.type === 'polygon' || ann.type === 'segmentation') {
          return [ann.points];
        }
        return [];
      })
      .filter((poly) => poly.length > 0);

    // Compute the union of all annotation polygons
    let union = [];
    if (annotationPolygons.length > 0) {
      union = polygonClipping.union(...annotationPolygons);
    }

    // Compute the difference between the image polygon and the union
    const backgroundPolygons = polygonClipping.difference(
      imagePolygon,
      union
    );

    if (!backgroundPolygons || backgroundPolygons.length === 0) {
      alert('No empty space to fill with background.');
      return;
    }

    // Convert backgroundPolygons to annotation format
    const backgroundAnnotations = backgroundPolygons.map((poly) => ({
      type: 'polygon',
      points: poly[0].map((pt) => ({ x: pt.x, y: pt.y })),
      label: labelName,
      color: labelColor,
    }));

    // Update annotations
    const updatedAnnotations = [...currentShapes, ...backgroundAnnotations];
    handleAnnotationsChange(updatedAnnotations);

    alert(`Background filled with label "${labelName}".`);
  };
  // -------------- End of Fill Background Feature --------------

  return (
    <div className="annotate-container">
      <AnnotationTopBar
        onHome={() => navigate('/')}
        onPrev={handlePrev}
        onNext={handleNext}
        onSave={handleSave}
        onZoomIn={handleZoomIn}
        onZoomOut={handleZoomOut}
        onExport={openExport}
        currentIndex={currentIndex}
        total={files.length}
        taskName={taskName}
      />

      <div style={{ padding: '8px', background: '#eee' }}>
        <button onClick={undo} style={{ marginRight: '8px' }}>
          Undo (Ctrl+Z)
        </button>
        <button onClick={redo} style={{ marginRight: '8px' }}>
          Redo (Ctrl+Y)
        </button>
      </div>

      <div className="annotate-main">
        {/* Tools Sidebar */}
        <div className="tools-sidebar">
          <h3>Tools</h3>
          <label>
            <input
              type="radio"
              name="tool"
              value="move"
              checked={selectedTool === 'move'}
              onChange={() => setSelectedTool('move')}
            />
            <span className="tool-icon">👆</span> Move (M)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="bbox"
              checked={selectedTool === 'bbox'}
              onChange={() => setSelectedTool('bbox')}
            />
            <span className="tool-icon">⬛</span> BBox (B)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polygon"
              checked={selectedTool === 'polygon'}
              onChange={() => setSelectedTool('polygon')}
            />
            <span className="tool-icon">🔺</span> Polygon (P)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polyline"
              checked={selectedTool === 'polyline'}
              onChange={() => setSelectedTool('polyline')}
            />
            <span className="tool-icon">📈</span> Polyline (L)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="point"
              checked={selectedTool === 'point'}
              onChange={() => setSelectedTool('point')}
            />
            <span className="tool-icon">📍</span> Point (O)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="ellipse"
              checked={selectedTool === 'ellipse'}
              onChange={() => setSelectedTool('ellipse')}
            />
            <span className="tool-icon">⬭</span> Ellipse (E)
          </label>

          {/* Segmentation */}
          <label>
            <input
              type="radio"
              name="tool"
              value="segmentation"
              checked={selectedTool === 'segmentation'}
              onChange={() => setSelectedTool('segmentation')}
            />
            <span className="tool-icon">🎨</span> Segmentation (S)
          </label>
          {selectedTool === 'segmentation' && (
            <div style={{ marginLeft: '20px', marginBottom: '8px' }}>
              <label style={{ display: 'block', marginBottom: '4px' }}>
                Type:
              </label>
              <select
                value={segmentationType}
                onChange={(e) => setSegmentationType(e.target.value)}
              >
                <option value="instance">Instance</option>
                <option value="semantic">Semantic</option>
                <option value="panoptic">Panoptic</option>
              </select>
            </div>
          )}

          <h3 style={{ marginTop: 16 }}>Active Label</h3>
          <select
            value={selectedLabelClass}
            onChange={(e) => setSelectedLabelClass(e.target.value)}
          >
            {currentLabelClasses.map((lc, i) => (
              <option key={i} value={lc.name}>
                {lc.name}
              </option>
            ))}
          </select>

          {/* Added: Fill Background Button */}
          <button
            onClick={handleFillBackground}
            style={{ marginTop: '16px', padding: '8px', width: '100%' }}
          >
            Fill Background
          </button>
          {/* End of Fill Background Button */}

          <div className="note-area">
            <p><strong>Shortcuts:</strong></p>
            <ul>
              <li>M/B/P/L/O/E => Tools</li>
              <li>S => Segmentation</li>
              <li>Ctrl+S => Save</li>
              <li>Esc => Cancel shape</li>
              <li>ArrowLeft => Prev image</li>
              <li>ArrowRight => Next image</li>
              <li>Ctrl+Z => Undo</li>
              <li>Ctrl+Y => Redo</li>
              <li>Ctrl+C => Copy selected</li>
              <li>Ctrl+V => Paste annotation</li>
            </ul>
          </div>
        </div>

        {/* Canvas */}
        <div className="canvas-area">
          {currentFileUrl ? (
            <AnnotationCanvas
              fileUrl={currentFileUrl}
              annotations={currentShapes}
              onAnnotationsChange={handleAnnotationsChange}
              selectedTool={selectedTool}
              scale={scale}
              onWheelZoom={handleWheelZoom}
              activeLabelColor={
                currentLabelClasses.find((l) => l.name === selectedLabelClass)?.color ||
                '#ff0000'
              }
              onFinishShape={handleFinishShape}
              onDeleteAnnotation={handleDeleteAnnotation}
              activeLabel={selectedLabelClass}
              labelClasses={currentLabelClasses}
              // Pass segmentationType to the canvas
              segmentationType={segmentationType}
              onImageLoad={setImageDimensions} // Added: Callback to receive image dimensions
            />
          ) : (
            <div style={{ textAlign: 'center', margin: 'auto' }}>
              No images found
            </div>
          )}
        </div>

        <AnnotationListSidebar
          annotations={currentShapes}
          onDeleteAnnotation={handleDeleteAnnotation}
          onUpdateAnnotation={handleUpdateAnnotation}
          labelClasses={currentLabelClasses}
        />
      </div>

      {exportOpen && (
        <div className="export-modal-backdrop">
          <div className="export-modal">
            <h2>Export Annotations</h2>
            <p>Select format:</p>
            <div className="export-buttons">
              <button onClick={() => exportAnnotations('coco')}>COCO</button>
              <button onClick={() => exportAnnotations('yolo')}>YOLO</button>
              <button onClick={() => exportAnnotations('pascal')}>Pascal VOC</button>
            </div>
            <button className="close-btn" onClick={closeExport}>
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
